import pytest

DEFERRED_STATUSES = {"deferred", "pending"}
BLOCKED_HTTP_CODES = {202, 403}

def test_withdrawal_to_new_biller_within_hold_period_is_deferred(
    auth_headers, api_client, new_biller_in_hold
):
    biller_id = new_biller_in_hold["id"]
    withdrawal_payload = {"amount": "50.00", "currency": "AUD"}

    resp = api_client.post(
        f"/billers/{biller_id}/withdrawals",
        json=withdrawal_payload,
        headers=auth_headers
    )

    assert resp.status_code in BLOCKED_HTTP_CODES, (
        f"Expected one of {BLOCKED_HTTP_CODES}, got {resp.status_code}: {resp.text}"
    )

    body = resp.json()
    if resp.status_code == 202:
        assert body.get("status") in DEFERRED_STATUSES, (
            f"Expected deferred/pending status, got {body.get('status')}"
        )
    else:
        assert body.get("error_code") == "BILLER_IN_HOLD", (
            f"Expected BILLER_IN_HOLD error_code, got {body.get('error_code')}"
        )

    # Verify no immediate debit occurred
    account_resp = api_client.get("/accounts/balance", headers=auth_headers)
    assert account_resp.status_code == 200
    balance_after = float(account_resp.json()["available_balance"])
    balance_before = float(new_biller_in_hold["account_balance_before"])
    assert balance_after == balance_before, (
        f"Balance changed unexpectedly: before={balance_before}, after={balance_after}"
    )
